import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/geminiService';
import { Message } from '../types';

const ChatAssistant: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: '안녕하세요. 복무지도관 및 복무관리담당자님을 위한 지능형 복무규정 지원 서비스입니다. 궁금하신 규정이나 처리하기 어려운 민원 사례에 대해 물어봐 주세요.',
      timestamp: new Date(),
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMessage: Message = {
      role: 'user',
      content: input,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      let fullResponse = "";
      const modelMessage: Message = {
        role: 'model',
        content: "",
        timestamp: new Date(),
      };

      setMessages(prev => [...prev, modelMessage]);

      await geminiService.sendMessageStream(input, (chunk) => {
        fullResponse += chunk;
        setMessages(prev => {
          const last = prev[prev.length - 1];
          if (last.role === 'model') {
            return [...prev.slice(0, -1), { ...last, content: fullResponse }];
          }
          return prev;
        });
      });
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        content: '죄송합니다. 서버와 통신 중 오류가 발생했습니다. 다시 시도해 주세요.',
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const suggestions = [
    "사회복무요원 연가 규정 알려줘",
    "복무이탈 시 경고 발부 절차는?",
    "겸직 허가 기준이 뭐야?",
    "정신건강 고충 상담 처리 방법"
  ];

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto border bg-white rounded-2xl shadow-sm">
      <div className="p-4 border-b flex items-center justify-between bg-slate-50/50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600">
            🤖
          </div>
          <div>
            <h2 className="text-sm font-bold">규정 상담 AI 헬퍼</h2>
            <p className="text-[10px] text-slate-500">실시간 규정 분석 중</p>
          </div>
        </div>
        <button className="text-xs text-blue-600 font-medium hover:underline">대화 기록 다운로드</button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-slate-100 text-slate-800 rounded-tl-none border border-slate-200 shadow-sm'
            }`}>
              <div className="whitespace-pre-wrap">{msg.content}</div>
              <p className={`text-[10px] mt-1 opacity-60 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-slate-100 px-4 py-3 rounded-2xl border border-slate-200 animate-pulse text-xs text-slate-500">
              답변을 생성하고 있습니다...
            </div>
          </div>
        )}
      </div>

      <div className="p-4 border-t bg-slate-50/50">
        {messages.length < 3 && (
          <div className="flex flex-wrap gap-2 mb-4">
            {suggestions.map((s, i) => (
              <button 
                key={i} 
                onClick={() => setInput(s)}
                className="text-[11px] bg-white border border-slate-200 px-3 py-1.5 rounded-full hover:bg-blue-50 hover:border-blue-200 transition-colors text-slate-600"
              >
                {s}
              </button>
            ))}
          </div>
        )}
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="규정이나 사례에 대해 물어보세요..."
            className="flex-1 border border-slate-300 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="bg-blue-600 text-white px-5 py-3 rounded-xl hover:bg-blue-700 disabled:opacity-50 transition-colors shadow-md shadow-blue-900/10"
          >
            전송
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-2">
          AI 답변은 참고용이며 최종 결정은 관련 법령 및 훈령을 재확인하시기 바랍니다.
        </p>
      </div>
    </div>
  );
};

export default ChatAssistant;

