const Library: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const filtered = MOCK_REGULATIONS.filter(reg => 
    reg.title.includes(searchTerm) || reg.summary.includes(searchTerm) || reg.category.includes(searchTerm)
  );

  const getCategoryStyles = (category: string) => {
    switch (category) {
      case '법률': return 'bg-indigo-600 text-white';
      case '시행령': return 'bg-purple-500 text-white';
      case '시행규칙': return 'bg-pink-500 text-white';
      case '훈령': return 'bg-blue-500 text-white';
      default: return 'bg-slate-500 text-white';
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      <div className="sticky top-0 z-20 bg-slate-50/90 backdrop-blur-md pt-2 pb-4 px-2">
        <div className="relative">
          <input
            type="text"
            placeholder="법령 또는 규정 명칭 검색..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-2xl text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
          />
          <span className="absolute left-4 top-3.5 text-slate-400 text-sm">🔍</span>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4 pb-20 px-2">
        {filtered.map((reg) => (
          <div key={reg.id} className="bg-white border border-slate-100 rounded-3xl p-5 shadow-sm active:scale-[0.98] transition-all flex flex-col gap-3">
            <div className="flex justify-between items-start">
              <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-lg ${getCategoryStyles(reg.category)}`}>
                {reg.category}
              </span>
            </div>
            <h3 className="text-base font-bold text-slate-900 leading-tight">
              {reg.title}
            </h3>
            <p className="text-[12px] text-slate-500 leading-relaxed line-clamp-2">
              {reg.summary}
            </p>
            <div className="flex items-center justify-between pt-3 mt-auto border-t border-slate-50">
              <span className="text-[10px] text-slate-400 font-medium tracking-tight uppercase">National Law Center</span>
              {reg.url ? (
                <a 
                  href={reg.url} 
                  target="_blank" 
                  rel="noopener noreferrer" 
                  className="flex items-center gap-1 text-xs font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl hover:bg-blue-100 transition-colors"
                >
                  법령센터 보기 ↗
                </a>
              ) : (
                <button className="text-xs font-bold text-blue-600">
                  상세보기
                </button>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Floating AI Search Bar or Entry */}
      <div className="fixed bottom-24 left-4 right-4 z-40 md:hidden">
        <button className="w-full bg-slate-900 text-white px-6 py-4 rounded-3xl font-black text-sm shadow-xl flex items-center justify-between border border-white/10 active:scale-95 transition-all">
          <span>🤖 AI에게 규정 해석 물어보기</span>
          <span className="bg-blue-500 px-2 py-0.5 rounded text-[10px]">VER 2.0</span>
        </button>
      </div>
    </div>
  );
};

